package com.hospital.management.service.impl;
import com.hospital.management.dao.*;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.util.*;import com.hospital.management.validation.*;import org.slf4j.*;import java.sql.*;import java.time.LocalDate;import java.util.*;
/** Transaction coordinator for optional linked patient accounts. */
public class PatientServiceImpl implements PatientService{private static final Logger LOG=LoggerFactory.getLogger(PatientServiceImpl.class);@FunctionalInterface public interface ConnectionProvider{Connection get()throws SQLException;}@FunctionalInterface public interface NumberProvider{String next()throws SQLException;}private final PatientDao patients;private final UserDao users;private final RoleDao roles;private final PatientValidator validator;private final AuditLogDao audit;private final ConnectionProvider connections;private final NumberProvider numbers;
 public PatientServiceImpl(){this(new PatientDaoImpl(),new UserDaoImpl(),new RoleDaoImpl(),new PatientValidator(),new AuditLogDaoImpl(),DatabaseConnectionManager::getConnection,PatientNumberGenerator::next);}public PatientServiceImpl(PatientDao p,UserDao u,RoleDao r,PatientValidator v,AuditLogDao a){this(p,u,r,v,a,DatabaseConnectionManager::getConnection,PatientNumberGenerator::next);}public PatientServiceImpl(PatientDao p,UserDao u,RoleDao r,PatientValidator v,AuditLogDao a,ConnectionProvider c,NumberProvider n){patients=p;users=u;roles=r;validator=v;audit=a;connections=c;numbers=n;}
 public Page<Patient> listPatients(PageRequest r,String status){PageRequest q=r==null?new PageRequest(1,10,""):r;String s=status==null||!Set.of("ACTIVE","INACTIVE").contains(status.toUpperCase())?null:status.toUpperCase();try{return patients.findAll(q,s);}catch(Exception e){LOG.error("Patient listing failed",e);return new Page<>(List.of(),q.getPageNumber(),q.getPageSize(),0);}}public Optional<Patient> getPatient(Long id){if(id==null||id<=0)return Optional.empty();try{return patients.findById(id);}catch(SQLException e){LOG.error("Patient lookup failed",e);return Optional.empty();}}
 public ServiceResult<Long> createPatient(PatientForm f,AuditContext a){if(f==null)return fail(ServiceResult.Status.VALIDATION_ERROR,"Patient details are required");norm(f);ValidationResult v=validator.validateCreate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Please correct the highlighted fields",v.getErrors());try{if(blank(f.getPatientNumber()))f.setPatientNumber(numbers.next());if(patients.existsByPatientNumber(f.getPatientNumber()))return dup("patientNumber");Long role=null;if(f.isCreateLoginAccount()){if(users.usernameExists(f.getUsername()))return dup("username");if(users.emailExists(f.getEmail()))return dup("email");role=roles.findRoleIdByName("PATIENT").orElse(null);if(role==null)return system();}Long roleId=role;Patient p=patient(f);long id=tx(c->{if(f.isCreateLoginAccount()){User u=user(f,roleId);p.setUserId(users.create(c,u));}return patients.createPatientRecord(c,p);});event("PATIENT_CREATED",id,a);if(f.isCreateLoginAccount())event("PATIENT_LOGIN_ACCOUNT_CREATED",id,a);return ServiceResult.success("Patient created",id);}catch(SQLException e){LOG.error("Patient creation failed",e);return SqlExceptionUtil.isUniqueConstraintViolation(e)?dup("patientNumber"):system();}}
 public ServiceResult<Void> updatePatient(PatientForm f,AuditContext a){if(f==null||f.getPatientId()==null)return failv(ServiceResult.Status.NOT_FOUND,"Patient not found");norm(f);try{Optional<Patient> old=patients.findById(f.getPatientId());if(old.isEmpty())return failv(ServiceResult.Status.NOT_FOUND,"Patient not found");Patient existing=old.get();ValidationResult v=validator.validateEdit(f,existing.getUserId()!=null);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Please correct the highlighted fields",v.getErrors());if(patients.existsByPatientNumberExcludingId(f.getPatientNumber(),f.getPatientId()))return dupv("patientNumber");boolean create=existing.getUserId()==null&&f.isCreateLoginAccount();if(existing.getUserId()!=null||create){if(existing.getUserId()!=null){if(users.usernameExistsExcludingUser(f.getUsername(),existing.getUserId()))return dupv("username");if(users.emailExistsExcludingUser(f.getEmail(),existing.getUserId()))return dupv("email");}else{if(users.usernameExists(f.getUsername()))return dupv("username");if(users.emailExists(f.getEmail()))return dupv("email");}}Long role=create?roles.findRoleIdByName("PATIENT").orElse(null):null;if(create&&role==null)return systemv();Patient p=patient(f);p.setPatientId(f.getPatientId());tx(c->{Long uid=existing.getUserId();if(create){uid=users.create(c,user(f,role));if(!patients.linkUserAccount(c,f.getPatientId(),uid))throw new SQLException("Patient account link failed");}else if(uid!=null){String us="LOCKED".equals(existing.getUserStatus())?"LOCKED":f.getStatus();required(users.updateUserIdentity(c,uid,f.getUsername(),f.getEmail(),us));if(!blank(f.getPassword()))required(users.updatePassword(c,uid,PasswordUtil.hashPassword(f.getPassword())));}required(patients.updatePatientRecord(c,p));return null;});event("PATIENT_UPDATED",f.getPatientId(),a);if(create)event("PATIENT_LOGIN_ACCOUNT_CREATED",f.getPatientId(),a);return ServiceResult.success("Patient updated",null);}catch(SQLException e){LOG.error("Patient update failed",e);return SqlExceptionUtil.isUniqueConstraintViolation(e)?dupv("patientNumber"):systemv();}}
 public ServiceResult<Void> activatePatient(Long id,AuditContext a){try{Optional<Patient> o=id==null?Optional.empty():patients.findById(id);if(o.isEmpty())return failv(ServiceResult.Status.NOT_FOUND,"Patient not found");Patient p=o.get();if("LOCKED".equals(p.getUserStatus()))return failv(ServiceResult.Status.CONFLICT,"Locked account must be unlocked separately");tx(c->{required(patients.updatePatientStatus(c,id,"ACTIVE"));if(p.getUserId()!=null)required(users.updateStatus(c,p.getUserId(),"ACTIVE"));return null;});event("PATIENT_ACTIVATED",id,a);return ServiceResult.success("Patient activated",null);}catch(SQLException e){LOG.error("Patient activation failed",e);return systemv();}}
 public ServiceResult<Void> deactivatePatient(Long id,AuditContext a){try{Optional<Patient> o=id==null?Optional.empty():patients.findById(id);if(o.isEmpty())return failv(ServiceResult.Status.NOT_FOUND,"Patient not found");if(patients.hasFutureAppointments(id)||patients.hasActiveAdmission(id)){event("PATIENT_DEACTIVATION_BLOCKED",id,a);return failv(ServiceResult.Status.CONFLICT,"Patient has a future appointment or active admission");}Patient p=o.get();tx(c->{required(patients.updatePatientStatus(c,id,"INACTIVE"));if(p.getUserId()!=null)required(users.updateStatus(c,p.getUserId(),"INACTIVE"));return null;});event("PATIENT_DEACTIVATED",id,a);return ServiceResult.success("Patient deactivated",null);}catch(SQLException e){LOG.error("Patient deactivation failed",e);return systemv();}}
 private<T>T tx(Work<T>w)throws SQLException{try(Connection c=connections.get()){boolean ac=c.getAutoCommit();try{c.setAutoCommit(false);T x=w.run(c);c.commit();return x;}catch(SQLException|RuntimeException e){try{c.rollback();}catch(SQLException x){e.addSuppressed(x);}throw e;}finally{try{c.setAutoCommit(ac);}catch(SQLException e){LOG.warn("Auto-commit restore failed",e);}}}}@FunctionalInterface private interface Work<T>{T run(Connection c)throws SQLException;}private void required(boolean b)throws SQLException{if(!b)throw new SQLException("Expected row was not updated");}
 private Patient patient(PatientForm f){Patient p=new Patient();p.setPatientNumber(f.getPatientNumber());p.setFirstName(f.getFirstName());p.setLastName(f.getLastName());p.setDateOfBirth(LocalDate.parse(f.getDateOfBirth()));p.setGender(f.getGender());p.setBloodGroup(f.getBloodGroup());p.setPhone(f.getPhone());p.setEmail(f.getEmail());p.setAddress(f.getAddress());p.setEmergencyContactName(f.getEmergencyContactName());p.setEmergencyContactPhone(f.getEmergencyContactPhone());p.setStatus(f.getStatus());return p;}private User user(PatientForm f,Long role){User u=new User();u.setUsername(f.getUsername());u.setEmail(f.getEmail());u.setPasswordHash(PasswordUtil.hashPassword(f.getPassword()));u.setRoleId(role);u.setStatus(f.getStatus());return u;}
 private void norm(PatientForm f){f.setPatientNumber(up(f.getPatientNumber()));f.setFirstName(tr(f.getFirstName()));f.setLastName(tr(f.getLastName()));f.setDateOfBirth(tr(f.getDateOfBirth()));f.setGender(up(f.getGender()));f.setBloodGroup(up(f.getBloodGroup()));f.setPhone(tr(f.getPhone()));f.setEmail(lo(f.getEmail()));f.setAddress(tr(f.getAddress()));f.setEmergencyContactName(tr(f.getEmergencyContactName()));f.setEmergencyContactPhone(tr(f.getEmergencyContactPhone()));f.setStatus(up(f.getStatus()));f.setUsername(lo(f.getUsername()));}private String tr(String s){return s==null?null:s.trim();}private String up(String s){String x=tr(s);return x==null?null:x.toUpperCase(Locale.ROOT);}private String lo(String s){String x=tr(s);return x==null?null:x.toLowerCase(Locale.ROOT);}private boolean blank(String s){return s==null||s.isBlank();}
 private void event(String e,Long id,AuditContext a){try{AuditContext x=a==null?new AuditContext(null,null,null):a;audit.recordEvent(e,x.userId(),"PATIENT",id,x.ipAddress(),x.userAgent());}catch(RuntimeException x){LOG.warn("Patient audit failed: {}",e,x);}}private<T>ServiceResult<T> fail(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private ServiceResult<Void> failv(ServiceResult.Status s,String m){return fail(s,m);}private ServiceResult<Long> dup(String f){return ServiceResult.failure(ServiceResult.Status.DUPLICATE,"Duplicate patient account data",Map.of(f,"Already exists"));}private ServiceResult<Void> dupv(String f){return ServiceResult.failure(ServiceResult.Status.DUPLICATE,"Duplicate patient account data",Map.of(f,"Already exists"));}private ServiceResult<Long> system(){return fail(ServiceResult.Status.SYSTEM_ERROR,"Patient service is temporarily unavailable");}private ServiceResult<Void> systemv(){return fail(ServiceResult.Status.SYSTEM_ERROR,"Patient service is temporarily unavailable");}}
